package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases adds a handful of *new* edge‑case
// scenarios for Order.CalculateTotal().  All of the existing tests
// (TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalNilItems, …)
// already cover the “happy‑path” cases, empty slices, large orders,
// float‑precision, etc.  The sub‑tests below focus on situations that
// are **not** exercised elsewhere:
//
//   1. items that contain a *negative* price – the method does **not**
//      perform validation, it simply sums price*quantity.
//   2. items with a *zero* quantity – they should contribute nothing.
//   3. items whose price is NaN – the resulting total must be NaN.
//   4. items whose price is +Inf – the total must be +Inf.
//   5. items whose price/quantity product overflows float64 – the total
//      should become +Inf (the IEEE‑754 overflow behaviour).
//
// The test follows the same table‑driven pattern used throughout the
// project (t.Run for each sub‑test) and does **not** duplicate any of the
// already‑existing test cases.

func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	tests := []struct {
		name        string
		items       []OrderItem
		wantTotal   float64
		wantIsNaN   bool
		wantIsInf   bool
		wantInfSign int // +1 for +Inf, -1 for -Inf, 0 otherwise
	}{
		{
			name: "NegativePrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -50.0},
			},
			wantTotal: -100.0,
		},
		{
			name: "ZeroQuantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 3, Price: 10.0},
			},
			// 0*123.45 + 3*10 = 30
			wantTotal: 30.0,
		},
		{
			name: "NaNPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 5, Price: 20.0},
			},
			// NaN propagates through the sum
			wantIsNaN: true,
		},
		{
			name: "InfPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.Inf(1)},
				{ProductID: 2, Quantity: 2, Price: 10.0},
			},
			wantIsInf:   true,
			wantInfSign: 1,
		},
		{
			name: "OverflowToInf",
			items: []OrderItem{
				// 1e308 * 10 = 1e309 → +Inf in float64
				{ProductID: 1, Quantity: 10, Price: 1e308},
			},
			wantIsInf:   true,
			wantInfSign: 1,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if tt.wantIsNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			if tt.wantIsInf {
				if !math.IsInf(o.Total, tt.wantInfSign) {
					t.Fatalf("expected Total to be %sInf, got %v",
						func() string {
							if tt.wantInfSign > 0 {
								return "+"
							}
							if tt.wantInfSign < 0 {
								return "-"
							}
							return ""
						}(),
						o.Total)
				}
				return
			}
			if o.Total != tt.wantTotal {
				t.Fatalf("expected Total %v, got %v", tt.wantTotal, o.Total)
			}
		})
	}
}
```

