)

// ---------------------------------------------------------------------
// Helper structs that mirror the request payloads used by the API.
// ---------------------------------------------------------------------

type categoryReq struct {
	Name        string `json:"name"`
	Slug        string `json:"slug,omitempty"`
	Description string `json:"description,omitempty"`
	SortOrder   int    `json:"sort_order,omitempty"`
}

type productReq struct {
	Name        string  `json:"name"`
	CategoryID  int64   `json:"category_id"`
	Description string  `json:"description,omitempty"`
	ImageURL    string  `json:"image_url,omitempty"`
	Price       float64 `json:"price"`
	InStock     bool    `json:"in_stock,omitempty"`
}

type orderItemReq struct {
	ProductID int64   `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price,omitempty"` // ignored – set by the use‑case
}

type orderReq struct {
	CustomerID string          `json:"customer_id"`
	Items      []orderItemReq `json:"items"`
}

// ---------------------------------------------------------------------
// TestFullFlow creates a category → product → order → process → complete.
// ---------------------------------------------------------------------

func TestAPIOrderFullFlow_CreateCategoryProductOrderProcessComplete(t *testing.T) {
	// -----------------------------------------------------------------
	// 1. Spin up a fresh in‑memory server (the same helper used by all
	//    other API tests).  The server contains the full handler stack:
	//    repos → use‑cases → chi router.
	// -----------------------------------------------------------------
	ts := setupTestServer(t) // defined in testhelper_test.go
	defer ts.Close()

	// -----------------------------------------------------------------
	// 2. CREATE CATEGORY
	// -----------------------------------------------------------------
	catPayload := categoryReq{
		Name:        "Кофе",
		Slug:        "coffee",
		Description: "Все виды кофе",
		SortOrder:   1,
	}
	catResp := postJSON(t, ts.URL+"/categories", catPayload)
	if catResp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for category, got %d", catResp.StatusCode)
	}
	var catCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp, &catCreated)

	// -----------------------------------------------------------------
	// 3. CREATE PRODUCT (belongs to the category we just created)
	// -----------------------------------------------------------------
	prodPayload := productReq{
		Name:        "Латте",
		CategoryID:  catCreated.ID,
		Description: "Молочный кофе",
		ImageURL:    "https://example.com/latte.png",
		Price:       350.0,
		InStock:     true,
	}
	prodResp := postJSON(t, ts.URL+"/products", prodPayload)
	if prodResp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for product, got %d", prodResp.StatusCode)
	}
	var prodCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp, &prodCreated)

	// -----------------------------------------------------------------
	// 4. CREATE ORDER (price is filled by the use‑case, we only send
	//    product_id and quantity)
	// -----------------------------------------------------------------
	orderPayload := orderReq{
		CustomerID: "alice@example.com",
		Items: []orderItemReq{
			{ProductID: prodCreated.ID, Quantity: 3},
		},
	}
	orderResp := postJSON(t, ts.URL+"/orders", orderPayload)
	if orderResp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for order, got %d", orderResp.StatusCode)
	}
	var orderCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, orderResp, &orderCreated)

	// -----------------------------------------------------------------
	// 5. PROCESS the order (POST /orders/{id}/process)
	// -----------------------------------------------------------------
	processURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderCreated.ID, 10), "process")
	processResp := doPost(t, processURL, nil)
	if processResp.StatusCode != http.StatusOK {
		t.Fatalf("expected 200 OK on process, got %d", processResp.StatusCode)
	}

	// -----------------------------------------------------------------
	// 6. COMPLETE the order (POST /orders/{id}/complete)
	// -----------------------------------------------------------------
	completeURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderCreated.ID, 10), "complete")
	completeResp := doPost(t, completeURL, nil)
	if completeResp.StatusCode != http.StatusOK {
		t.Fatalf("expected 200 OK on complete, got %d", completeResp.StatusCode)
	}

	// -----------------------------------------------------------------
	// 7. VERIFY final state (GET /orders/{id})
	// -----------------------------------------------------------------
	getURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderCreated.ID, 10))
	getResp := doGet(t, getURL)
	if getResp.StatusCode != http.StatusOK {
		t.Fatalf("expected 200 OK on GET order, got %d", getResp.StatusCode)
	}
	var orderOut struct {
		ID         int64   `json:"id"`
		CustomerID string  `json:"customer_id"`
		Status     string  `json:"status"` // should be "completed"
		Total      float64 `json:"total"`
		Items      []struct {
			ProductID int64   `json:"product_id"`
			Quantity  int     `json:"quantity"`
			Price     float64 `json:"price"`
		} `json:"items"`
	}
	decodeBody(t, getResp, &orderOut)

	if orderOut.Status != string(handler.OrderStatusCompleted) {
		t.Fatalf("expected order status %q, got %q", handler.OrderStatusCompleted, orderOut.Status)
	}
	// The total must be price*quantity (350 * 3 = 1050)
	expectedTotal := prodPayload.Price * float64(orderPayload.Items[0].Quantity)
	if orderOut.Total != expectedTotal {
		t.Fatalf("expected total %.2f, got %.2f", expectedTotal, orderOut.Total)
	}
	if len(orderOut.Items) != 1 {
		t.Fatalf("expected exactly one order item, got %d", len(orderOut.Items))
	}
	if orderOut.Items[0].Price != prodPayload.Price {
		t.Fatalf("expected item price %.2f, got %.2f", prodPayload.Price, orderOut.Items[0].Price)
	}
}

