## 4. Переписать тяжёлые интеграционные тесты в **табличный** стиль

### Проблема
* `TestIntegrationProductList` и `TestIntegrationProductPaginationBoundary` содержат почти одинаковый код создания 10‑20 продуктов, а потом проверяют разные комбинации `offset/limit`.  
* Тесты повторяют `repo.Create` в каждом `t.Run`.

### Действие
Создать **один набор данных** в `setupOnce` (через `sync.Once`) и переиспользовать его в подпотоках:

```go
var (
    productSetup sync.Once
    productIDs   []int64
)

func ensureProducts(t *testing.T, repo repository.ProductRepository) {
    productSetup.Do(func() {
        for i := 1; i <= 20; i++ {
            p := entity.Product{
                CategoryID: 1,
                Name:       fmt.Sprintf("Prod-%02d", i),
                Price:      float64(i) * 10,
            }
            id, err := repo.Create(context.Background(), &p)
            if err != nil {
                t.Fatalf("seed product %d: %v", i, err)
            }
            productIDs = append(productIDs, id)
        }
    })
}
```

Тогда в тесте

**Файл:** `entity/order_test.go`

```go
package entity

import (
	"math"
	"reflect"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – новые edge‑case‑тесты для метода
// Order.CalculateTotal().  Они не пересекаются с уже существующими
// TestUnitOrderCalculateTotal* и TestUnitOrderCalculateTotal*Extended.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// исходный набор элементов, который будем копировать в каждый sub‑test.
	baseItems := []OrderItem{
		{ProductID: 1, Quantity: 1, Price: 10.0},
		{ProductID: 2, Quantity: 2, Price: 20.0},
	}

	tests := []struct {
		name          string
		modifyItems   func([]OrderItem) []OrderItem // меняет копию baseItems
		expectedTotal float64
		expectInf     bool // true → ожидаем math.Inf(+1) в результате
	}{
		{
			name: "extremely_large_price_overflows_to_inf",
			modifyItems: func(items []OrderItem) []OrderItem {
				// 1 × (math.MaxFloat64) → Inf после умножения на 2
				items[0].Price = math.MaxFloat64
				items[0].Quantity = 2
				return items
			},
			expectedTotal: math.Inf(+1),
			expectInf:     true,
		},
		{
			name: "extremely_large_quantity_overflows_to_inf",
			modifyItems: func(items []OrderItem) []OrderItem {
				// 2 × (math.MaxInt64) → Inf (float64 overflow)
				items[0].Price = 1.0
				items[0].Quantity = math.MaxInt64
				return items
			},
			expectedTotal: math.Inf(+1),
			expectInf:     true,
		},
		{
			name: "negative_price_is_allowed_by CalculateTotal",
			modifyItems: func(items []OrderItem) []OrderItem {
				// Валидация продукта не проверяется в CalculateTotal,
				// поэтому отрицательная цена просто вычитается из суммы.
				items[0].Price = -15.0
				items[0].Quantity = 1
				return items
			},
			expectedTotal: -15.0 + 2*20.0, // -15 + 40 = 25
			expectInf:     false,
		},
		{
			name: "zero_quantity_does_not_change_total",
			modifyItems: func(items []OrderItem) []OrderItem {
				items[0].Quantity = 0 // 0 × 10 = 0
				return items
			},
			expectedTotal: 0 + 2*20.0, // 40
			expectInf:     false,
		},
		{
			name: "zero_price_and_quantity_mix",
			modifyItems: func(items []OrderItem) []OrderItem {
				// первый элемент – цена 0, второй – количество 0
				items[0].Price = 0
				items[0].Quantity = 5
				items[1].Price = 30
				items[1].Quantity = 0
				return items
			},
			expectedTotal: 0, // 0*5 + 30*0 = 0
			expectInf:     false,
		},
		{
			name: "items_slice_unchanged_after_calculation",
			modifyItems: func(items []OrderItem) []OrderItem {
				// просто копируем базовый набор – проверяем, что CalculateTotal
				// не мутирует структуру OrderItem.
				return items
			},
			expectedTotal: 1*10.0 + 2*20.0, // 50
			expectInf:     false,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Подготавливаем копию baseItems, чтобы каждый sub‑test работал с
			// независимым срезом.
			itemsCopy := make([]OrderItem, len(baseItems))
			copy(itemsCopy, baseItems)
			if tt.modifyItems != nil {
				itemsCopy = tt.modifyItems(itemsCopy)
			}

			o := Order{
				Items: itemsCopy,
			}
			o.CalculateTotal()

			// 1️⃣ Проверяем значение Total.
			if tt.expectInf {
				if !math.IsInf(o.Total, +1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
			} else {
				if diff := math.Abs(o.Total - tt.expectedTotal); diff > 1e-9 {
					t.Fatalf("unexpected Total: want %v, got %v (diff %v)", tt.expectedTotal, o.Total, diff)
				}
			}

			// 2️⃣ Убеждаемся, что CalculateTotal не изменил элементы заказа.
			// (Только для последнего кейса – «items_slice_unchanged_after_calculation»)
			if tt.name == "items_slice_unchanged_after_calculation" {
				if !reflect.DeepEqual(o.Items, itemsCopy) {
					t.Fatalf("order items were mutated; want %+v, got %+v", itemsCopy, o.Items)
				}
			}
		})
	}
}
```

