```go
// TestAPIOrderFullFlow creates a category, a product, an order and then
// runs the whole order life‑cycle: Process → Complete.
// It exercises the whole stack (router → handlers → use‑cases → repositories)
// with a fresh in‑memory SQLite DB, exactly the way the other API tests do.
func TestAPIOrderFullFlow(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣  Test‑infrastructure – fresh DB + full HTTP server
	// --------------------------------------------------------------------
	// setupTestServer(t) is defined in testhelper_test.go. It creates:
	//   * SQLite in‑memory DB (RunMigrations)
	//   * all 4 repositories (product, category, news, order)
	//   * all 4 use‑cases
	//   * chi router with every handler mounted
	//   * httptest.Server that we talk to via ordinary HTTP calls.
	srv := setupTestServer(t)
	defer srv.Close()

	// --------------------------------------------------------------------
	// 2️⃣  Helper shortcuts – they are already used by the other API tests
	// --------------------------------------------------------------------
	// createCategory, createProduct and createTestOrderAPI are defined in
	// testhelper_test.go. They hide the JSON‑marshalling, request‑sending
	// and response‑decoding boiler‑plate.
	//
	//   createCategory(t, srv.URL, name, slug, description) → Category
	//   createProduct(t, srv.URL, prod) → Product
	//   createTestOrderAPI(t, srv.URL, orderReq) → Order (with items)
	//
	// All helpers call t.Fatalf on any unexpected status code, so the test
	// stops immediately if something goes wrong.

	// --------------------------------------------------------------------
	// 3️⃣  Create a **Category**
	// --------------------------------------------------------------------
	cat := createCategory(t,
		srv.URL,
		"Кофе",          // name
		"coffee",        // slug
		"Тестовая категория для полного flow", // description
	)

	// --------------------------------------------------------------------
	// 4️⃣  Create a **Product** that belongs to the category we just made
	// --------------------------------------------------------------------
	prod := createProduct(t,
		srv.URL,
		// Product payload – fields match entity.Product
		struct {
			Name        string  `json:"name"`
			CategoryID  int64   `json:"category_id"`
			Description string  `json:"description,omitempty"`
			Price       float64 `json:"price"`
			ImageURL    string  `json:"image_url,omitempty"`
			InStock     bool    `json:"in_stock,omitempty"`
		}{
			Name:        "Латте",
			CategoryID:  cat.ID,
			Description: "Классический латте",
			Price:       350.0,
			ImageURL:    "", // optional
			InStock:     true,
		},
	)

	// --------------------------------------------------------------------
	// 5️⃣  **Create** an Order (this also checks that the use‑case fills
	//     the item.Price from the product price and calculates Total)
	// --------------------------------------------------------------------
	orderReq := struct {
		CustomerID string `json:"customer_id"`
		Items []struct {
			ProductID int64 `json:"product_id"`
			Quantity  int   `json:"quantity"`
		} `json:"items"`
	}{
		CustomerID: "alice@example.com",
		Items: []struct {
			ProductID int64 `json:"product_id"`
			Quantity  int   `json:"quantity"`
		}{
			{ProductID: prod.ID, Quantity: 3},
		},
	}
	ord := createTestOrderAPI(t, srv.URL, orderReq)

	// --------------------------------------------------------------------
	// 6️⃣  Verify the **initial** state of the order
	// --------------------------------------------------------------------
	if got, want := ord.Status, "new"; got != want {
		t.Fatalf("order status after creation = %q, want %q", got, want)
	}
	if got, want := ord.Total, prod.Price*3; got != want {
		t.Fatalf("order total = %v, want %v (price*qty)", got, want)
	}
	if len(ord.Items) != 1 {
		t.Fatalf("order items count = %d, want 1", len(ord.Items))
	}
	if got, want := ord.Items[0].Price, prod.Price; got != want {
		t.Fatalf("order item price = %v, want %v (product price)", got, want)
	}

	// --------------------------------------------------------------------
	// 7️⃣  **Process** the order – POST /orders/{id}/process
	// --------------------------------------------------------------------
	processURL := fmt.Sprintf("%s/orders/%d/process", srv.URL, ord.ID)
	req, _ := http.NewRequest(http.MethodPost, processURL, nil)
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Fatalf("POST /process request failed: %v", err)
	}
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("process returned %d, want %d", resp.StatusCode, http.StatusOK)
	}
	resp.Body.Close()

	// --------------------------------------------------------------------
	// 8️⃣  Fetch the order again and verify the **processing** state
	// --------------------------------------------------------------------
	ord = getOrderByID(t, srv.URL, ord.ID)
	if got, want := ord.Status, "processing"; got != want {
		t.Fatalf("order status after process = %q, want %q", got, want)
	}

	// --------------------------------------------------------------------
	// 9️⃣  **Complete** the order – POST /orders/{id}/complete
	// --------------------------------------------------------------------
	completeURL := fmt.Sprintf("%s/orders/%d/complete", srv.URL, ord.ID)
	req, _ = http.NewRequest(http.MethodPost, completeURL, nil)
	resp, err = http.DefaultClient.Do(req)
	if err != nil {
		t.Fatalf("POST /complete request failed: %v", err)
	}
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("complete returned %d, want %d", resp.StatusCode, http.StatusOK)
	}
	resp.Body.Close()

	// --------------------------------------------------------------------
	// 10️⃣  Final verification – order must be in **completed** state
	// --------------------------------------------------------------------
	ord = getOrderByID(t, srv.URL, ord.ID)
	if got, want := ord.Status, "completed"; got != want {
		t.Fatalf("final order status = %q, want %q", got, want)
	}
}

// ---------------------------------------------------------------------------
// Helper used only in this file – a thin wrapper around GET /orders/{id}
// ---------------------------------------------------------------------------
func getOrderByID(t *testing.T, baseURL string, id int64) *struct {
	ID         int64   `json:"id"`
	CustomerID string  `json:"customer_id"`
	Status     string  `json:"status"`
	Total      float64 `json:"total"`
	Items      []struct {
		ID        int64   `json:"id"`
		ProductID int64   `json:"product_id"`
		Quantity  int     `json:"quantity"`
		Price     float64 `json:"price"`
	} `json:"items"`
} {
	url := fmt.Sprintf("%s/orders/%d", baseURL, id)
	resp, err := http.Get(url)
	if err != nil {
		t.Fatalf("GET /orders/%d failed: %v", id, err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET /orders/%d returned %d, want %d", id, resp.StatusCode, http.StatusOK)
	}
	var o struct {
		ID         int64   `json:"id"`
		CustomerID string  `json:"customer_id"`
		Status     string  `json:"status"`
		Total      float64 `json:"total"`
		Items      []struct {
			ID        int64   `json:"id"`
			ProductID int64   `json:"product_id"`
			Quantity  int     `json:"quantity"`
			Price     float64 `json:"price"`
		} `json:"items"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&o); err != nil {
		t.Fatalf("decoding order JSON: %v", err)
	}
	return &o
}
