package handlers

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"path"
	"strconv"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/yourorg/beanbrew/internal/api/helpers"
	"github.com/yourorg/beanbrew/internal/domain"
	"github.com/yourorg/beanbrew/internal/infrastructure"
	"github.com/yourorg/beanbrew/internal/repository"
	"github.com/yourorg/beanbrew/internal/usecase"
)

// ---------------------------------------------------------------------------
// Helper structs that mimic the request payloads used by the API
// ---------------------------------------------------------------------------
type categoryReq struct {
	Name        string `json:"name"`
	Slug        string `json:"slug,omitempty"`
	Description string `json:"description,omitempty"`
	SortOrder   int    `json:"sort_order,omitempty"`
}

type productReq struct {
	Name        string  `json:"name"`
	CategoryID  int64   `json:"category_id"`
	Description string  `json:"description,omitempty"`
	ImageURL    string  `json:"image_url,omitempty"`
	Price       float64 `json:"price"`
	InStock     bool    `json:"in_stock,omitempty"`
}

type orderReq struct {
	CustomerID string               `json:"customer_id"`
	Items      []orderItemReq      `json:"items"`
}

type orderItemReq struct {
	ProductID int64   `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price,omitempty"` // ignored by the API – set by use‑case
}

// ---------------------------------------------------------------------------
// Test: full end‑to‑end flow (category → product → order → process → complete)
// ---------------------------------------------------------------------------
func TestAPIOrderFullFlow(t *testing.T) {
	// -----------------------------------------------------------------------
	// 1. Set up a fresh in‑memory SQLite DB and the whole HTTP stack.
	// -----------------------------------------------------------------------
	db := infrastructure.SetupTestDB(t) // creates :memory: DB and runs migrations
	// repositories
	catRepo := repository.NewSQLiteCategoryRepo(db)
	prodRepo := repository.NewSQLiteProductRepo(db)
	orderRepo := repository.NewSQLiteOrderRepo(db)

	// use‑cases
	catUC := usecase.NewCategoryUseCase(catRepo)
	prodUC := usecase.NewProductUseCase(prodRepo, catRepo)
	orderUC := usecase.NewOrderUseCase(orderRepo, prodRepo)

	// handlers
	catH := NewCategoryHandler(catUC)
	prodH := NewProductHandler(prodUC)
	orderH := NewOrderHandler(orderUC)

	// router (the same as in the production server)
	r := chi.NewRouter()
	r.Mount("/categories", catH.Routes())
	r.Mount("/products", prodH.Routes())
	r.Mount("/orders", orderH.Routes())

	ts := httptest.NewServer(r)
	defer ts.Close()

	// -----------------------------------------------------------------------
	// 2. Create a category (POST /categories)
	// -----------------------------------------------------------------------
	catPayload := categoryReq{
		Name: "Кофе",
		Slug: "coffee",
	}
	catResp := struct {
		ID int64 `json:"id"`
	}{}
	helpers.PostJSON(t, ts.URL+"/categories", catPayload, &catResp, http.StatusCreated)

	if catResp.ID == 0 {
		t.Fatalf("category creation returned id=0")
	}

	// -----------------------------------------------------------------------
	// 3. Create a product that belongs to the category (POST /products)
	// -----------------------------------------------------------------------
	prodPayload := productReq{
		Name:       "Латте",
		CategoryID: catResp.ID,
		Price:      350.0,
		InStock:    true,
	}
	prodResp := struct {
		ID int64 `json:"id"`
	}{}
	helpers.PostJSON(t, ts.URL+"/products", prodPayload, &prodResp, http.StatusCreated)

	if prodResp.ID == 0 {
		t.Fatalf("product creation returned id=0")
	}

	// -----------------------------------------------------------------------
	// 4. Create an order that references the product (POST /orders)
	// -----------------------------------------------------------------------
	orderPayload := orderReq{
		CustomerID: "alice@example.com",
		Items: []orderItemReq{
			{
				ProductID: prodResp.ID,
				Quantity:  3,
			},
		},
	}
	orderResp := struct {
		ID int64 `json:"id"`
	}{}
	helpers.PostJSON(t, ts.URL+"/orders", orderPayload, &orderResp, http.StatusCreated)

	if orderResp.ID == 0 {
		t.Fatalf("order creation returned id=0")
	}

	// -----------------------------------------------------------------------
	// 5. Process the order (POST /orders/{id}/process)
	// -----------------------------------------------------------------------
	processURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderResp.ID, 10), "process")
	helpers.DoRequest(t, http.MethodPost, processURL, nil, http.StatusOK)

	// Verify that the status changed to “processing”
	got := getOrder(t, ts.URL, orderResp.ID)
	if got.Status != string(domain.OrderStatusProcessing) {
		t.Fatalf("expected status %q after processing, got %q", domain.OrderStatusProcessing, got.Status)
	}

	// -----------------------------------------------------------------------
	// 6. Complete the order (POST /orders/{id}/complete)
	// -----------------------------------------------------------------------
	completeURL := ts.URL + path.Join("/orders", strconv.FormatInt(orderResp.ID, 10), "complete")
	helpers.DoRequest(t, http.MethodPost, completeURL, nil, http.StatusOK)

	// Verify that the status changed to “completed”
	got = getOrder(t, ts.URL, orderResp.ID)
	if got.Status != string(domain.OrderStatusCompleted) {
		t.Fatalf("expected status %q after completion, got %q", domain.OrderStatusCompleted, got.Status)
	}
}

// ---------------------------------------------------------------------------
// Helper: GET /orders/{id} and decode the JSON payload into a struct.
// ---------------------------------------------------------------------------
func getOrder(t *testing.T, baseURL string, id int64) *domain.Order {
	t.Helper()
	url := baseURL + path.Join("/orders", strconv.FormatInt(id, 10))
	resp, err := http.Get(url)
	if err != nil {
		t.Fatalf("GET order %d failed: %v", id, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET order %d returned status %d, want %d", id, resp.StatusCode, http.StatusOK)
	}

	var o domain.Order
	if err := json.NewDecoder(resp.Body).Decode(&o); err != nil {
		t.Fatalf("decoding order %d response: %v", id, err)
	}
	return &o
}
```

### What the test does, step by step

| Step | HTTP call | Expected result | Relevant test / function |
|------|-----------|----------------|--------------------------|
| 1️⃣   | `POST /categories` | `201 Created` + JSON `{ "id": <int64> }` | `helpers.PostJSON` (used throughout the API‑handler tests) |
| 2️⃣   | `POST /products` | `201 Created` + JSON `{ "id": <int64> }` | same helper as above |
| 3️⃣   | `POST /orders` | `201 Created` + JSON `{ "id": <int64> }` | same helper |
| 4️⃣   | `POST /orders/{id}/process` | `200 OK` | `helpers.DoRequest` (simple wrapper that checks status) |
| 5️⃣   | `GET  /orders/{id}` | JSON with `status = "processing"` | `getOrder` helper |
| 6️⃣   | `POST /orders/{id}/complete` | `200 OK` | `helpers.DoRequest` |
| 7️⃣   | `GET  /orders/{id}` | JSON with `status = "completed"` | `getOrder` helper |

### Why this fits the existing test‑suite

* **Naming convention** – All API‑handler tests start with `TestAPI…`. The new test follows that (`TestAPIOrderFullFlow`).
* **Isolation** – The test creates its own in‑memory SQLite DB (`SetupTestDB(t)`) exactly like the other API tests (`setupTestServer` does the same internally). No state leaks between tests.
* **Reuse of helpers** – The project already ships `helpers.PostJSON`, `helpers.DoRequest`, and the `setupTestServer`‑style router construction. The test re‑uses those helpers, keeping the style
